#!/usr/bin/env bash
source "$(dirname "${BASH_SOURCE[0]}")/android-test.sh"
archphene_test_live_theme(){ local serial="$1" package="$2" label="$3";archphene_test_init "$serial";local activity old_mode pid child pid2 child2 tmp;activity="$(archphene_launcher "$package")";old_mode="$(archphene_adb_run shell cmd uimode night|tr -d '\r')";tmp="$(archphene_mktemp_dir live-theme)";archphene_adb_run shell cmd uimode night no;archphene_adb_run shell am start -W -n "$activity" >/dev/null;sleep 6;pid="$(archphene_adb_run shell pidof "$package"|tr -d '\r')";child="$(archphene_adb_run shell ps -A -o PID,PPID,NAME|awk -v p="$pid" '$2==p{print $1;exit}')";archphene_adb_run shell screencap -p /sdcard/theme-light.png;archphene_adb_run pull /sdcard/theme-light.png "$tmp/light.png" >/dev/null;archphene_adb_run shell cmd uimode night yes;sleep 4;pid2="$(archphene_adb_run shell pidof "$package"|tr -d '\r')";child2="$(archphene_adb_run shell ps -A -o PID,PPID,NAME|awk -v p="$pid2" '$2==p{print $1;exit}')";archphene_adb_run shell screencap -p /sdcard/theme-dark.png;archphene_adb_run pull /sdcard/theme-dark.png "$tmp/dark.png" >/dev/null;[[ "$pid" == "$pid2" && "$child" == "$child2" ]] || archphene_die "$label restarted during live theme change";! cmp -s "$tmp/light.png" "$tmp/dark.png" || archphene_die "$label rendering did not change";case "$old_mode" in *yes*)archphene_adb_run shell cmd uimode night yes;;*)archphene_adb_run shell cmd uimode night no;;esac;archphene_note "$label live theme passed on $serial with Android PID $pid and Linux PID $child.";}
